[GRAPH] parsel.utils.shorten
def shorten(text: str, width: int, suffix: str = "...") -> str:
    if len(text) <= width:
        return text
    if width > len(suffix):
        return text[: width - len(suffix)] + suffix
    if width >= 0:
        return suffix[len(suffix) - width :]
    raise ValueError("width must be equal or greater than 0")

